import { useCallback, useState } from 'react';

import Stack from '@mui/material/Stack';
import Tab from '@mui/material/Tab';
import Tabs from '@mui/material/Tabs';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

function TabPanel({ value, index, children }) {
  if (value !== index) return null;
  return <div>{children}</div>;
}

export default function MissionsPage() {
  const [tab, setTab] = useState(0);

  const ownerLabelBuilder = useCallback((owner) => `${owner.parcel_code} - ${owner.full_name} (${owner.rut})`, []);
  const userLabelBuilder = useCallback((user) => `${user.username} (${user.role})`, []);
  const missionLabelBuilder = useCallback((mission) => mission.title, []);

  const ownerOptions = useSelectOptions('/maps/parcel-options/', ownerLabelBuilder, { include_inactive: 'true' });
  const userOptions = useSelectOptions('/users/', userLabelBuilder);
  const missionOptions = useSelectOptions('/missions/missions/', missionLabelBuilder);

  return (
    <Stack sx={{ gap: 2 }}>
      <Tabs value={tab} onChange={(_, value) => setTab(value)}>
        <Tab label="Misiones" />
        <Tab label="Vuelos de Dron" />
        <Tab label="Reportes Operativos" />
      </Tabs>

      <TabPanel value={tab} index={0}>
        <CrudResourceModule
          title="Misiones"
          path="/missions/missions/"
          columns={[
            { key: 'title', label: 'Titulo' },
            { key: 'mission_type', label: 'Tipo' },
            { key: 'team_name', label: 'Equipo' },
            { key: 'assigned_to_username', label: 'Asignado' },
            { key: 'status', label: 'Estado' }
          ]}
          fields={() => [
            { name: 'title', label: 'Titulo', required: true },
            { name: 'description', label: 'Descripcion', type: 'textarea', fullWidth: true },
            { name: 'mission_type', label: 'Tipo mision' },
            { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: [{ value: '', label: 'Sin propietario' }, ...ownerOptions] },
            { name: 'team_name', label: 'Equipo' },
            { name: 'assigned_to', label: 'Asignado a', type: 'select', options: [{ value: '', label: 'Sin asignar' }, ...userOptions] },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'planned', label: 'Planificada' },
                { value: 'in_progress', label: 'En curso' },
                { value: 'done', label: 'Completada' },
                { value: 'cancelled', label: 'Cancelada' }
              ],
              required: true
            },
            { name: 'scheduled_for', label: 'Programada para', type: 'datetime-local' },
            { name: 'started_at', label: 'Inicio', type: 'datetime-local' },
            { name: 'completed_at', label: 'Fin', type: 'datetime-local' }
          ]}
          mapPayload={(values) => ({
            ...values,
            owner: values.owner || null,
            assigned_to: values.assigned_to || null
          })}
          defaultOrdering="-scheduled_for"
          searchPlaceholder="Buscar por titulo, tipo, equipo, propietario o parcela..."
        />
      </TabPanel>

      <TabPanel value={tab} index={1}>
        <CrudResourceModule
          title="Vuelos de Dron"
          path="/missions/drone-flights/"
          columns={[
            { key: 'flight_datetime', label: 'Fecha/Hora' },
            { key: 'mission_code', label: 'Mision' },
            { key: 'team_code', label: 'Equipo' },
            { key: 'owner_display', label: 'Parcela / Propietario' },
            { key: 'pilot_username', label: 'Piloto' },
            { key: 'battery_code', label: 'Bateria' },
            { key: 'takeoff_platform', label: 'Plataforma' }
          ]}
          fields={() => [
            { name: 'flight_datetime', label: 'Fecha/Hora vuelo', type: 'datetime-local', required: true },
            { name: 'mission_code', label: 'Codigo mision', required: true },
            { name: 'team_code', label: 'Equipo', required: true },
            { name: 'pilot', label: 'Piloto', type: 'select', options: [{ value: '', label: 'Sin piloto' }, ...userOptions] },
            { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: [{ value: '', label: 'Sin parcela' }, ...ownerOptions] },
            { name: 'battery_code', label: 'Bateria' },
            { name: 'takeoff_platform', label: 'Plataforma despegue' },
            { name: 'photo_path', label: 'Ruta foto' },
            { name: 'video_path', label: 'Ruta video' },
            { name: 'notes', label: 'Novedades', type: 'textarea', fullWidth: true }
          ]}
          mapPayload={(values) => ({
            ...values,
            pilot: values.pilot || null,
            owner: values.owner || null
          })}
          defaultOrdering="-flight_datetime"
          searchPlaceholder="Buscar por mision, equipo, piloto, bateria o parcela..."
        />
      </TabPanel>

      <TabPanel value={tab} index={2}>
        <CrudResourceModule
          title="Reportes Operativos"
          path="/missions/mission-reports/"
          columns={[
            { key: 'mission', label: 'Mision' },
            { key: 'report_date', label: 'Fecha' },
            { key: 'created_by_username', label: 'Usuario' },
            { key: 'media_type', label: 'Media' }
          ]}
          fields={() => [
            { name: 'mission', label: 'Mision', type: 'select', options: missionOptions, required: true },
            { name: 'report_date', label: 'Fecha reporte', type: 'date', required: true },
            { name: 'summary', label: 'Resumen', type: 'textarea', fullWidth: true, required: true },
            { name: 'media_url', label: 'URL media', fullWidth: true },
            {
              name: 'media_type',
              label: 'Tipo media',
              type: 'select',
              options: [
                { value: 'none', label: 'Ninguno' },
                { value: 'image', label: 'Imagen' },
                { value: 'video', label: 'Video' }
              ],
              required: true
            }
          ]}
          defaultOrdering="-report_date"
          extraFilters={[
            {
              key: 'created_by',
              label: 'Usuario',
              options: userOptions
            }
          ]}
        />
      </TabPanel>
    </Stack>
  );
}

